//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Font table elements:
//!        font/name/charset/family/pitch/panose1/sig/altName/notTrueType".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-emission rule mined
//! from ECMA-376 / ISO 29500 / MS-OI29500 (see the `refs:` on each test). A
//! FAILING assertion is NOT a flaky test to silence: it encodes a real
//! Word-compliance gap in the stemma engine. Do not weaken an assertion to make
//! it green — fix the engine, or (if the assertion itself is a test-bug per the
//! consumption-vs-save methodology) re-classify it as an oracle question.
//!
//! Methodology guard (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim. So `reserialize()` of an unedited document reflects
//! stemma's verbatim-preservation contract, not Word's render-time
//! normalization. The xml* assertions here only check things stemma's
//! serializer actively reproduces (verbatim link-key preservation, ordering,
//! structural validity) — never "Word ignores value V on layout". Consumption
//! semantics are checked on the READ side (accept/reject text).

use std::io::Read;

use stemma::api::Document;

// ─── Prelude ─────────────────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body> … </w:body></w:document>`. `extra_parts` is a list of
/// `(part_path, part_xml)` (e.g. `("word/styles.xml", "<w:styles…/>")`); each is
/// added to the zip and gets a `[Content_Types].xml` override.
#[allow(dead_code)]
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for extra parts, keyed by known part path.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = content_type_for(path);
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Document rels: one relationship per extra part so the part is reachable
    // (Target is relative to word/).
    let mut doc_rel_entries = String::new();
    for (i, (path, _)) in extra_parts.iter().enumerate() {
        let target = path.strip_prefix("word/").unwrap_or(path);
        let rel_type = rel_type_for(path);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

fn content_type_for(path: &str) -> &'static str {
    match path {
        "word/styles.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        }
        "word/numbering.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        }
        "word/fontTable.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.fontTable+xml"
        }
        other => panic!("make_docx: no content-type mapping for extra part {other}"),
    }
}

fn rel_type_for(path: &str) -> &'static str {
    match path {
        "word/styles.xml" => {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
        }
        "word/numbering.xml" => {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
        }
        "word/fontTable.xml" => {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/fontTable"
        }
        other => panic!("make_docx: no rel-type mapping for extra part {other}"),
    }
}

/// Unzip `docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip for reading");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in docx");
    let mut s = String::new();
    file.read_to_string(&mut s)
        .expect("read document.xml utf-8");
    s
}

/// Parse `bytes` into a `Document`, serialize with default export options, and
/// return the resulting `word/document.xml`. This is the serializer's actual
/// output for the parsed model (verbatim for untouched content).
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse docx");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize docx");
    document_xml_of(&out)
}

/// Assert `stemma::api::validate(bytes)` reports no errors. The public
/// `ValidationReport` exposes `ok: bool` + `issues`; the issues are rendered into
/// the panic message so a failure is self-explanatory.
#[allow(dead_code)]
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{ctx} — expected the package to open clean (validate ok), but got issues: {:?}",
        report.issues
    );
}

