/// ECMA-376 §17.8.3.10, §17.3.2.26; MS-OI29500 §2.1.262.
/// An rFonts/@ascii name is an opaque ST_String link key, never comma-split.
#[test]
fn rfonts_ascii_name_with_comma_is_single_link_key() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Foo, Bar" w:hAnsi="Foo, Bar"/></w:rPr><w:t>hello</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:ascii="Foo, Bar""#),
        "§17.8.3.10 (refs: ECMA-376 §17.8.3.10/§17.3.2.26, MS-OI29500 §2.1.262) — \
         the rFonts name is the verbatim link key; the comma is part of the single \
         ST_String name and must be re-emitted intact, not split into 'Foo'/'Bar'. \
         Got document.xml:\n{xml}"
    );
    assert!(
        !xml.contains(r#"w:ascii="Foo""#),
        "MS-OI29500 §2.1.262 (refs: ECMA-376 §17.8.3.10) — Word never splits a font \
         name on commas, so the engine must not emit a truncated 'Foo' link key. \
         Got document.xml:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "§17.8.3.10 — a comma-containing typeface name is a valid ST_String; opens without repair",
    );
}

/// ECMA-376 §17.8.2, §17.8.3.10; ISO 29500-1 §17.13.5.16.
/// Absent-font run inside w:ins: substitution is render-time, so accept keeps
/// the inserted text, reject drops it, package opens clean.
#[test]
fn absent_font_substitution_inside_w_ins_preserves_tracking() {
    let body = r#"<w:p><w:r><w:t>base </w:t></w:r><w:ins w:id="1" w:author="a" w:date="2024-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:ascii="NoSuchFace-XYZ" w:hAnsi="NoSuchFace-XYZ"/></w:rPr><w:t>added</w:t></w:r></w:ins></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "base added",
        "§17.8.2 (refs: ECMA-376 §17.8.2/§17.8.3.10, ISO 29500-1 §17.13.5.16) — \
         substitution is render-time; an uninstalled font does not change that \
         accepting the insertion keeps the inserted text."
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "base".trim(),
        "§17.13.5.16 — rejecting an insertion removes exactly the inserted run text \
         regardless of which font it names. (baseline is 'base ')"
    );
    assert_opens_clean(
        &b,
        "§17.8.2 — a run naming an unavailable font is a valid substitution state; opens without repair",
    );
}

/// ECMA-376 §17.8.2, §17.8.3.10, §17.3.2.26.
/// Three distinct absent ascii/eastAsia/cs slots are each preserved verbatim,
/// none collapsed or silently guessed; document opens clean.
#[test]
fn three_distinct_absent_slots_no_silent_guess() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="FaceAsciiZZ" w:eastAsia="FaceEastZZ" w:cs="FaceCsZZ"/></w:rPr><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:ascii="FaceAsciiZZ""#),
        "§17.8.3.10 (refs: ECMA-376 §17.8.2/§17.8.3.10/§17.3.2.26) — the ascii link \
         key is preserved verbatim even though the face is uninstalled (no silent \
         guess). Got document.xml:\n{xml}"
    );
    assert!(
        xml.contains(r#"w:eastAsia="FaceEastZZ""#),
        "§17.3.2.26 (refs: §17.8.3.10) — the eastAsia slot is a distinct link key \
         and is not collapsed onto ascii. Got document.xml:\n{xml}"
    );
    assert!(
        xml.contains(r#"w:cs="FaceCsZZ""#),
        "§17.3.2.26 (refs: §17.8.3.10) — the cs slot is a distinct link key \
         preserved independently. Got document.xml:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "§17.8.2 — three uninstalled faces are a valid render-time substitution state; \
         the validator must not demand a font table",
    );
}

/// ECMA-376 §17.8.2, §17.3.2.26, §17.8.3.10.
/// rFonts on the paragraph-mark rPr naming an absent font is render-only; body
/// text is verbatim under accept and reject; opens clean.
#[test]
fn paragraph_mark_rfonts_absent_font_opens_clean_text_verbatim() {
    let body = r#"<w:p><w:pPr><w:rPr><w:rFonts w:ascii="GhostMarkFace" w:hAnsi="GhostMarkFace"/></w:rPr></w:pPr><w:r><w:t>visible text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "visible text",
        "§17.8.2 (refs: ECMA-376 §17.8.2/§17.3.2.26/§17.8.3.10) — the paragraph-mark \
         font is render-only; accepting (no revisions) reproduces the body text verbatim."
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "visible text",
        "§17.8.2 — an absent paragraph-mark font does not change run content on reject."
    );
    assert_opens_clean(
        &b,
        "§17.3.2.26 + §17.8.2 — rFonts on the paragraph-mark rPr naming an uninstalled \
         face is valid; the document opens without repair",
    );
}

/// ECMA-376 §17.8.2, §17.8.3.10; MS-OI29500 §2.1.262.
/// A run whose rFonts names a font with NO font-table entry (no fontTable.xml)
/// opens clean and keeps the authored name verbatim (no save-time rewrite to a
/// resolved substitute in document.xml — that rewrite, per MS-OI §2.1.262, lives
/// in the font table's altName, an oracle-only question).
#[test]
fn rfonts_names_absent_font_table_opens_clean_no_rewrite() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Totally Made Up Font" w:hAnsi="Totally Made Up Font"/></w:rPr><w:t>substituted</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ECMA §17.8.2 (refs: §17.8.3.10, MS-OI29500 §2.1.262) — an unlocatable font is \
         resolved by render-time substitution, a valid state; the package must validate \
         with no errors",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains("Totally Made Up Font"),
        "§17.8.3.10 (refs: ECMA-376 §17.8.2, MS-OI29500 §2.1.262) — the rFonts name is \
         the authored link key; stemma preserves it verbatim and must not rewrite it to \
         a resolved substitute in the saved document.xml (the resolved-name rewrite lives \
         in the font table's altName, not in rFonts). Got document.xml:\n{xml}"
    );
}

/// ECMA-376 §17.8.3.10, §17.3.2.26; MS-OI29500 §2.1.88.
/// Distinct ascii/eastAsia/cs slots stay distinct through reserialize.
#[test]
fn rfonts_eastasia_cs_distinct_slots_text_preserved_both_resolutions() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Calibri" w:eastAsia="SimSun" w:cs="Arial"/></w:rPr><w:t>tri-slot</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:eastAsia="SimSun""#),
        "§17.8.3.10 (refs: ECMA-376 §17.8.3.10/§17.3.2.26, MS-OI29500 §2.1.88) — \
         eastAsia is a distinct link key; the serializer must not drop or collapse it \
         onto ascii. Got document.xml:\n{xml}"
    );
    assert!(
        xml.contains(r#"w:cs="Arial""#),
        "§17.8.3.10 (refs: §17.3.2.26, MS-OI29500 §2.1.88) — the cs slot is a distinct \
         link key preserved separately from ascii/eastAsia. Got document.xml:\n{xml}"
    );
}

/// ECMA-376 §17.3.2.26, §17.8.3.10; MS-OI29500 §2.1.88; ISO 29500-1 §17.13.5.16.
/// rFonts on a run in w:ins is a font property, not part of the revision: accept
/// keeps inserted text, reject drops exactly it, package opens clean.
#[test]
fn rfonts_in_ins_named_font_is_property_not_revision() {
    let body = r#"<w:p><w:r><w:t>base </w:t></w:r><w:ins w:id="7" w:author="a" w:date="2026-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:ascii="Consolas" w:hAnsi="Consolas"/></w:rPr><w:t>added</w:t></w:r></w:ins></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "base added",
        "§17.13.5.16 (refs: §17.3.2.26/§17.8.3.10, MS-OI29500 §2.1.88) — accepting an \
         insertion keeps the inserted text; the font name is a non-revision property and \
         does not affect the kept content."
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "base".trim(),
        "§17.13.5.16 — rejecting an insertion removes exactly the inserted run text; the \
         font property on that run is irrelevant to what is removed. (baseline is 'base ')"
    );
    assert_opens_clean(
        &b,
        "§17.8.2 — an inserted run naming an uninstalled font is a valid substitution \
         state; the package validates without repair",
    );
}

/// MS-OI29500 §2.1.270, ECMA-376 §17.8.3.10, ISO 29500-1 §17.13.5.14.
/// An '@'-prefixed vertical-text font name on a deleted run: reject restores the
/// deleted text, accept removes exactly the delText, opens clean.
#[test]
fn vertical_at_prefixed_font_in_w_del_tracked_semantics() {
    let body = r#"<w:p><w:r><w:t>keep </w:t></w:r><w:del w:id="2" w:author="a" w:date="2024-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:eastAsia="@MS Mincho"/></w:rPr><w:delText>gone</w:delText></w:r></w:del></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "keep gone",
        "§17.13.5.14 (refs: MS-OI29500 §2.1.270, ECMA-376 §17.8.3.10) — rejecting a \
         deletion restores the deleted text; the '@'-prefixed font name does not alter \
         restoration."
    );
    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "keep".trim(),
        "§17.13.5.14 — accepting a deletion removes exactly the delText regardless of the \
         run's font slot. (baseline is 'keep ')"
    );
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.270 — an '@'-prefixed vertical font name is a valid font \
         reference; the package opens without repair",
    );
}

