/// ECMA-376 §17.3.2.26, ISO 29500-1 §17.3.2 (CT_PPr/rPr paragraph-mark glyph),
/// MS-OI29500 §2.1.88.
/// rFonts in the paragraph-mark rPr selects the mark glyph font only; it does
/// not alter body run text under accept/reject and the package opens clean.
#[test]
fn rfonts_on_paragraph_mark_rpr_distinct_from_run_opens_clean() {
    let body = r#"<w:p><w:pPr><w:rPr><w:rFonts w:ascii="Cambria" w:hAnsi="Cambria"/></w:rPr></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Arial" w:hAnsi="Arial"/></w:rPr><w:t>Body run text.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    assert_opens_clean(
        &b,
        "§17.3.2.26 — rFonts is permitted in both pPr/rPr (paragraph-mark properties) and \
         run rPr; both reference fonts by name, so the package is structurally valid and \
         Word opens it without repair",
    );
    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Body run text.",
        "ISO 29500-1 §17.3.2 (refs: §17.3.2.26, MS-OI29500 §2.1.88) — the paragraph-mark \
         font slot governs the mark glyph, not run content; accepting leaves the run \
         characters unchanged (rFonts is a font property, not a revision)."
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Body run text.",
        "MS-OI29500 §2.1.88 — rejecting cannot remove a non-revision font property; the \
         body run text is reproduced verbatim regardless of the paragraph-mark font."
    );
}
